class OrderManager {
    constructor() {
      this.orders = JSON.parse(localStorage.getItem('orders')) || [];
      this.setupEventListeners();
    }

    setupEventListeners() {
      // Filter orders by status
      const statusFilters = document.querySelectorAll('.order-status-filter');
      if (statusFilters) {
        statusFilters.forEach(filter => {
          filter.addEventListener('click', (e) => {
            e.preventDefault();
            const status = e.target.dataset.status;
            this.filterOrdersByStatus(status);

            // Update active filter
            statusFilters.forEach(f => f.classList.remove('active'));
            e.target.classList.add('active');
          });
        });
      }

      // Order search functionality
      const searchInput = document.getElementById('order-search');
      if (searchInput) {
        searchInput.addEventListener('input', (e) => {
          this.searchOrders(e.target.value);
        });
      }

      // Order detail view
      document.addEventListener('click', (e) => {
        if (e.target.classList.contains('view-order-btn')) {
          const orderId = e.target.dataset.orderid;
          this.showOrderDetails(orderId);
        }
      });

      // Cancel order button
      document.addEventListener('click', (e) => {
        if (e.target.classList.contains('cancel-order-btn')) {
          const orderId = e.target.dataset.orderid;
          this.cancelOrder(orderId);
        }
      });

      // Return to order list from detail view
      const backToOrdersBtn = document.getElementById('back-to-orders');
      if (backToOrdersBtn) {
        backToOrdersBtn.addEventListener('click', () => {
          this.hideOrderDetails();
        });
      }
    }

    createOrder(orderData) {
      // Generate a unique order ID
      const orderId = 'ORD-' + Date.now().toString().slice(-6) + '-' + Math.floor(Math.random() * 1000);

      const newOrder = {
        id: orderId,
        date: new Date().toISOString(),
        status: 'processing',
        items: orderData.items,
        shipping: orderData.shipping,
        billing: orderData.billing,
        payment: orderData.payment,
        subtotal: orderData.subtotal,
        tax: orderData.tax,
        shippingCost: orderData.shippingCost,
        total: orderData.total,
        trackingNumber: null,
        estimatedDelivery: null
      };

      this.orders.unshift(newOrder); // Add to beginning of array
      this.saveOrders();

      return orderId;
    }

    updateOrderStatus(orderId, status) {
      const order = this.getOrderById(orderId);
      if (order) {
        order.status = status;

        // For shipped orders, generate a tracking number and estimated delivery
        if (status === 'shipped') {
          order.trackingNumber = this.generateTrackingNumber();

          // Set estimated delivery to 5-7 business days from now
          const deliveryDate = new Date();
          deliveryDate.setDate(deliveryDate.getDate() + 5 + Math.floor(Math.random() * 3));
          order.estimatedDelivery = deliveryDate.toISOString();
        }

        this.saveOrders();
        return true;
      }
      return false;
    }

    cancelOrder(orderId) {
      const order = this.getOrderById(orderId);
      if (order && ['processing', 'pending'].includes(order.status)) {
        if (confirm('Are you sure you want to cancel this order?')) {
          order.status = 'cancelled';
          this.saveOrders();
          this.renderOrders();
          this.hideOrderDetails();
          return true;
        }
      } else {
        alert('This order cannot be cancelled.');
      }
      return false;
    }

    getOrderById(orderId) {
      return this.orders.find(order => order.id === orderId);
    }

    getAllOrders() {
      return this.orders;
    }

    filterOrdersByStatus(status) {
      const ordersContainer = document.getElementById('orders-list');
      if (!ordersContainer) return;

      if (status === 'all') {
        this.renderOrders();
        return;
      }

      const filteredOrders = status === 'all' 
        ? this.orders 
        : this.orders.filter(order => order.status === status);

      this.renderOrdersList(filteredOrders);
    }

    searchOrders(query) {
      if (!query) {
        this.renderOrders();
        return;
      }

      query = query.toLowerCase();
      const filteredOrders = this.orders.filter(order => 
        order.id.toLowerCase().includes(query) || 
        this.formatDate(order.date).toLowerCase().includes(query)
      );

      this.renderOrdersList(filteredOrders);
    }

    showOrderDetails(orderId) {
      const order = this.getOrderById(orderId);
      if (!order) return;

      // Hide orders list and show detail view
      document.getElementById('orders-list-container').classList.add('hidden');
      const detailContainer = document.getElementById('order-detail-container');
      detailContainer.classList.remove('hidden');

      // Populate order details
      document.getElementById('detail-order-id').textContent = order.id;
      document.getElementById('detail-order-date').textContent = this.formatDate(order.date);
      document.getElementById('detail-order-status').textContent = this.formatStatus(order.status);
      document.getElementById('detail-order-status').className = `status-badge ${order.status}`;

      // Shipping address
      const shippingAddress = document.getElementById('detail-shipping-address');
      shippingAddress.innerHTML = this.formatAddress(order.shipping);

      // Billing address
      const billingAddress = document.getElementById('detail-billing-address');
      billingAddress.innerHTML = this.formatAddress(order.billing);

      // Payment method
      const paymentMethod = document.getElementById('detail-payment-method');
      paymentMethod.innerHTML = this.formatPayment(order.payment);

      // Order items
      const itemsList = document.getElementById('detail-order-items');
      itemsList.innerHTML = '';

      order.items.forEach(item => {
        const itemRow = document.createElement('tr');
        itemRow.innerHTML = `
          <td>
            <div class="item-info">
              <div class="item-image">
                <img src="${item.image || 'images/placeholder.jpg'}" alt="${item.name}">
              </div>
              <div class="item-name">${item.name}</div>
            </div>
          </td>
          <td>${item.quantity}</td>
          <td>$${item.price.toFixed(2)}</td>
          <td>$${(item.price * item.quantity).toFixed(2)}</td>
