        itemsList.appendChild(itemRow);
      });

      // Order summary
      document.getElementById('detail-subtotal').textContent = `$${order.subtotal.toFixed(2)}`;
      document.getElementById('detail-tax').textContent = `$${order.tax.toFixed(2)}`;
      document.getElementById('detail-shipping-cost').textContent = `$${order.shippingCost.toFixed(2)}`;
      document.getElementById('detail-total').textContent = `$${order.total.toFixed(2)}`;

      // Tracking info
      const trackingContainer = document.getElementById('tracking-info');
      if (order.trackingNumber && order.status === 'shipped') {
        trackingContainer.classList.remove('hidden');
        document.getElementById('tracking-number').textContent = order.trackingNumber;
        document.getElementById('estimated-delivery').textContent = this.formatDate(order.estimatedDelivery);
      } else {
        trackingContainer.classList.add('hidden');
      }

      // Cancel button - only show for orders that are processing or pending
      const cancelBtn = document.getElementById('cancel-order-btn');
      if (['processing', 'pending'].includes(order.status)) {
        cancelBtn.classList.remove('hidden');
        cancelBtn.dataset.orderid = order.id;
      } else {
        cancelBtn.classList.add('hidden');
      }
    }

    hideOrderDetails() {
      document.getElementById('orders-list-container').classList.remove('hidden');
      document.getElementById('order-detail-container').classList.add('hidden');
    }

    renderOrders() {
      this.renderOrdersList(this.orders);
    }

