          </div>
          <div class="order-summary">
            <div class="order-items-count">${itemCount} ${itemCount === 1 ? 'item' : 'items'}</div>
            <div class="order-total">$${order.total.toFixed(2)}</div>
          </div>
          <div class="order-actions">
            <button class="view-order-btn" data-orderid="${order.id}">View Order</button>
            ${['processing', 'pending'].includes(order.status) ? 
              `<button class="cancel-order-btn" data-orderid="${order.id}">Cancel</button>` : ''}
