          ${order.trackingNumber && order.status === 'shipped' ? `
            <div class="tracking-info-summary">
              <div>Tracking: ${order.trackingNumber}</div>
              <div>Est. Delivery: ${this.formatDate(order.estimatedDelivery)}</div>
