      const date = new Date(dateString);
      return date.toLocaleDateString('en-US', { 
        year: 'numeric', 
        month: 'long', 
        day: 'numeric' 
      });
    }

    formatStatus(status) {
      const statusMap = {
        'processing': 'Processing',
        'pending': 'Pending',
        'shipped': 'Shipped',
        'delivered': 'Delivered',
        'cancelled': 'Cancelled'
      };

      return statusMap[status] || status;
