      let icon = '';
      if (payment.type === 'credit') {
        icon = this.getCardIcon(payment.cardType);
      } else if (payment.type === 'paypal') {
        icon = '<i class="fa-brands fa-paypal"></i>';
      }

      let display = '';
      if (payment.type === 'credit') {
        display = `${payment.cardType} ending in ${payment.last4}`;
      } else if (payment.type === 'paypal') {
        display = `PayPal (${payment.email})`;
      }

      return `
        <div class="payment-method-display">
          ${icon}
          <span>${display}</span>
        </div>
      `;
    }

    getCardIcon(cardType) {
      const iconMap = {
        'Visa': '<i class="fa-brands fa-cc-visa"></i>',
        'Mastercard': '<i class="fa-brands fa-cc-mastercard"></i>',
        'American Express': '<i class="fa-brands fa-cc-amex"></i>',
        'Discover': '<i class="fa-brands fa-cc-discover"></i>'
      };

      return iconMap[cardType] || '<i class="fa-regular fa-credit-card"></i>';
    }

    init() {
      this.renderOrders();
    }
  }

  export default OrderManager;
